import{_ as t,o as e,c as o,a3 as r}from"./chunks/framework.CGpxwYOt.js";const h=JSON.parse('{"title":"4.3 对抗活动的展开","description":"本节点为目录/结构标题，具体操作内容见其下级章节。 不管是参与各种活动还是被邀请团队，最好都要先清楚这次是要干什么，可以打字询问，可以语音询问，只要不是打的正激动都会有人回答你的。 被邀请团队后，如果你没有空，请明说。大家不会计较的，如果你","frontmatter":{"title":"4.3 对抗活动的展开","description":"本节点为目录/结构标题，具体操作内容见其下级章节。 不管是参与各种活动还是被邀请团队，最好都要先清楚这次是要干什么，可以打字询问，可以语音询问，只要不是打的正激动都会有人回答你的。 被邀请团队后，如果你没有空，请明说。大家不会计较的，如果你","outline":"deep"},"headers":[],"relativePath":"war/4-3.md","filePath":"war/4-3.md","lastUpdated":1782387794000}'),d={name:"war/4-3.md"};function i(l,a,s,c,n,_){return e(),o("div",null,[...a[0]||(a[0]=[r('<h1 id="_4-3-对抗活动的展开" tabindex="-1">4.3 对抗活动的展开 <a id="s281-d81ced53"></a> <a class="header-anchor" href="#_4-3-对抗活动的展开" aria-label="Permalink to &quot;4.3 对抗活动的展开 &lt;a id=&quot;s281-d81ced53&quot;&gt;&lt;/a&gt;&quot;">​</a></h1><p>本节点为目录/结构标题，具体操作内容见其下级章节。</p><h2 id="_4-3-1-沟通的重要性" tabindex="-1">4.3.1 沟通的重要性 <a id="s282-3be93cff"></a> <a class="header-anchor" href="#_4-3-1-沟通的重要性" aria-label="Permalink to &quot;4.3.1 沟通的重要性 &lt;a id=&quot;s282-3be93cff&quot;&gt;&lt;/a&gt;&quot;">​</a></h2><p>不管是参与各种活动还是被邀请团队，最好都要先清楚这次是要干什么，可以打字询问，可以语音询问，只要不是打的正激动都会有人回答你的。</p><p>被邀请团队后，如果你没有空，请明说。大家不会计较的，如果你不知道是要干什么，如打劫还是被打劫，请及时询问。</p><h2 id="_4-3-2-语音的重要性" tabindex="-1">4.3.2 语音的重要性 <a id="s283-b8b8338a"></a> <a class="header-anchor" href="#_4-3-2-语音的重要性" aria-label="Permalink to &quot;4.3.2 语音的重要性 &lt;a id=&quot;s283-b8b8338a&quot;&gt;&lt;/a&gt;&quot;">​</a></h2><p>由于打字时不能打架，还有小概率卡顿闪退之类的，在一些紧急情况，打字不能很好的让其他玩家清楚你的情况，像打劫时也会延误最佳救援时间。如果你在语音，</p><p>你看到有人上船或者帝王飞过来，就可以一边在游戏里面应对，一边快速向其他玩家报告具体位置和具体情况，方便其他玩家快速判断如何救援。</p><h2 id="_4-3-3-如何组织对抗活动" tabindex="-1">4.3.3 如何组织对抗活动 <a id="s284-4e41fa7c"></a> <a class="header-anchor" href="#_4-3-3-如何组织对抗活动" aria-label="Permalink to &quot;4.3.3 如何组织对抗活动 &lt;a id=&quot;s284-4e41fa7c&quot;&gt;&lt;/a&gt;&quot;">​</a></h2><p>组织活动最好是QQ 群和语音一起通知，有时候一些事情不方便被敌对的老外知道，所以游戏内打字不保险，当然如果是被敌对势力知道也无所谓的情况，公屏打字通知在线玩家不失为一个好选择。</p><h2 id="_4-3-4-如何参与对抗活动" tabindex="-1">4.3.4 如何参与对抗活动 <a id="s285-c6bd216c"></a> <a class="header-anchor" href="#_4-3-4-如何参与对抗活动" aria-label="Permalink to &quot;4.3.4 如何参与对抗活动 &lt;a id=&quot;s285-c6bd216c&quot;&gt;&lt;/a&gt;&quot;">​</a></h2><p>在看到或听到相关信息后，确认情况后加入组织玩家的团队即可。有时候可能需要你私聊组织玩家，如果你不知道是谁，可以在语音和QQ 群里问。</p>',12)])])}const u=t(d,[["render",i]]);export{h as __pageData,u as default};
